package main

import (
	"html/template"
	"net/http"
)

type Comment struct {
	Author  string
	Content string
}

var comments = []Comment{
	{Author: "Alice", Content: "This is a great post! <strong>Thank you!</strong>"},
	{Author: "Bob", Content: "I found this very helpful."},
	{Author: "Charlie", Content: "<em>I have a question...</em>"},
}

func commentsHandler(w http.ResponseWriter, r *http.Request) {
	tmpl := `<html>
	<head>
		<title>User Comments</title>
	</head>
	<body>
		<h1>User Comments</h1>
		{{range .}}
			<div>
				<h3>{{.Author}}</h3>
				<p>{{.Content | html}}</p>
			</div>
		{{end}}
	</body>
</html>`

	t, err := template.New("comments").Funcs(template.FuncMap{
		"html": template.HTML,
	}).Parse(tmpl)
	if err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
		return
	}

	if err := t.Execute(w, comments); err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
	}
}

func main() {
	http.HandleFunc("/comments", commentsHandler)
	http.ListenAndServe(":8080", nil)
}